var e=[{id:`L3_1`,type:`dialog`,speaker:`MINA_FENRIR_CHIEF_NULL`,text:{KOREA:`커헉!`,JPN:`がはっ！`,ENG:`Kuh!`,TWN:`咳！`},stage:{bg:`MIND`,slots:{L:null,C:{char_id:`MINA_FENRIR_CHIEF_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_QM`,text:{KOREA:`아무리 날카로운 발톱을 가졌어도, 넌 나약해. 유미나.`,JPN:`いくら鋭い爪を持っていても、あなたは弱い。ヤナギ・ミナ。`,ENG:`Doesn't matter how sharp your claws are, Yoo Mina. You're weak.`,TWN:`不管你的爪子有多鋒利，你仍然是弱者，劉米娜。`},stage:{bg:`MIND`,slots:{L:{char_id:`MINA_FENRIR_CHIEF_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`YOOMINA_FENRIR_NEXT_QM`,face:`UNIT_SERIOUS`}}}},{id:`L8_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_QM`,text:{KOREA:`달려나갈 힘을 잃고, 상처 입고 웅크린 늑대일 뿐이지.`,JPN:`走る力を失い、傷ついて身をすくめた狼にすぎない。`,ENG:`You're just a wounded Wolf crouching in the corner with no strength to run.`,TWN:`你只是一隻受傷的、畏縮的、失去了奔跑力量的狼。`},stage:{bg:`MIND`,slots:{L:{char_id:`MINA_FENRIR_CHIEF_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`YOOMINA_FENRIR_NEXT_QM`,face:`UNIT_IDLE`}}}},{id:`L9_1`,type:`dialog`,speaker:`MINA_FENRIR_CHIEF_NULL`,text:{KOREA:`…시끄러워.`,JPN:`……黙れ。`,ENG:`...Shut it.`,TWN:`……吵死了。`},stage:{bg:`MIND`,slots:{L:{char_id:`MINA_FENRIR_CHIEF_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`YOOMINA_FENRIR_NEXT_QM`,face:`UNIT_IDLE`}}}},{id:`L11_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_QM`,text:{KOREA:`인생 전부가 꼭두각시처럼 남들 좋을 대로 이용당했잖아.`,JPN:`人生のすべてを操り人形のように他人に利用されてきた。`,ENG:`You've lived your whole life being used like a puppet.`,TWN:`你一輩子都像傀儡一樣被人利用。`},stage:{bg:`MIND`,slots:{L:{char_id:`MINA_FENRIR_CHIEF_NULL`,face:`UNIT_IDLE`},C:{char_id:`YOOMINA_FENRIR_NEXT_QM`,face:`UNIT_HATE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_QM`,text:{KOREA:`가장 소중히 여기던 것들은 전부 물거품처럼 사라졌고.`,JPN:`最も大事に思っていたことは全部、泡のように消えた。`,ENG:`The things you cherished the most have all turned to dust.`,TWN:`最重視的東西都化為泡沫。`},stage:{bg:`MIND`,slots:{L:{char_id:`MINA_FENRIR_CHIEF_NULL`,face:`UNIT_IDLE`},C:{char_id:`YOOMINA_FENRIR_NEXT_QM`,face:`UNIT_SERIOUS`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_QM`,text:{KOREA:`뭘 위해서 아직도 발버둥치는 건데?`,JPN:`何のためにまだもがいているんだ？`,ENG:`So what are you still struggling for?`,TWN:`你還在為什麼而掙扎？`},stage:{bg:`MIND`,slots:{L:{char_id:`MINA_FENRIR_CHIEF_NULL`,face:`UNIT_IDLE`},C:{char_id:`YOOMINA_FENRIR_NEXT_QM`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`MINA_FENRIR_CHIEF_NULL`,text:{KOREA:`하아… 과거의 난 왜 이리도 부정적인 건지 원.`,JPN:`はぁ...…過去の私って何でこんなにネガティブなのか。`,ENG:`*Sigh...* Why was I so pessimistic in the past?`,TWN:`唉……過去的我怎麼這麼消極。`},stage:{bg:`MIND`,slots:{L:{char_id:`MINA_FENRIR_CHIEF_NULL`,face:`UNIT_DESPAIR`},C:{char_id:`YOOMINA_FENRIR_NEXT_QM`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`MINA_FENRIR_CHIEF_NULL`,text:{KOREA:`너 말이야. 초호화 호텔에서 먹는 스테이크가 얼마나 맛있는지 알아?`,JPN:`あなたね。超豪華ホテルで食べるステーキがどんなに美味しいかわかる？`,ENG:`Hey, do you know how good a steak from a luxury hotel is?`,TWN:`你知道那些超豪華飯店的牛排有多好吃嗎？`},stage:{bg:`MIND`,slots:{L:{char_id:`MINA_FENRIR_CHIEF_NULL`,face:`UNIT_IDLE`},C:{char_id:`YOOMINA_FENRIR_NEXT_QM`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_QM`,text:{KOREA:`뭐…? 그게 무슨 뚱딴지 같은 소리…`,JPN:`は……？　それってどういう……`,ENG:`What...? What's that got to do with thi–`,TWN:`嗯……？你突然說什麼……`},stage:{bg:`MIND`,slots:{L:{char_id:`MINA_FENRIR_CHIEF_NULL`,face:`UNIT_IDLE`},C:{char_id:`YOOMINA_FENRIR_NEXT_QM`,face:`UNIT_SERIOUS`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_QM`,text:{KOREA:`큭?!`,JPN:`くっ！？`,ENG:`Kgh?!`,TWN:`咳？！`},stage:{bg:`MIND`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NEXT_QM`,face:`UNIT_HATE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`MINA_FENRIR_CHIEF_NULL`,text:{KOREA:`좌절한 적도 있었어.`,JPN:`挫折したこともあった。`,ENG:`There were times when I was frustrated.`,TWN:`我曾經沮喪過。`},stage:{bg:`MIND`,slots:{L:null,C:{char_id:`MINA_FENRIR_CHIEF_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`MINA_FENRIR_CHIEF_NULL`,text:{KOREA:`나는 처음부터 평범하게 학교나 다니며 살 수 없는 운명이었고…`,JPN:`私は最初から普通に学校に行くような生活は送れない運命で……`,ENG:`It was never my fate to live a normal life going to school and all that from the start.`,TWN:`我從一開始就註定過不了普通人的生活……`},stage:{bg:`MAINSTREAM_345013`,slots:{L:null,C:null,R:null}}},{id:`L27_1`,type:`dialog`,speaker:`MINA_FENRIR_CHIEF_NULL`,text:{KOREA:`그 운명이란 게 내 선택이 아닌 누군가의 뜻대로 조종당한 것일 뿐이라고 생각하면…`,JPN:`その運命が自分の選択ではなく、誰かによって操られただけだと思うと……`,ENG:`But to think that my fate was never up to me and was controlled by someone...`,TWN:`一想起我不能主動去選擇自己的命運，而只能被某個人的意願操縱……`},stage:{bg:`MAINSTREAM_345012`,slots:{L:null,C:null,R:null}}},{id:`L29_1`,type:`dialog`,speaker:`MINA_FENRIR_CHIEF_NULL`,text:{KOREA:`내가 살아온 이유가 부정 당하는 기분이었으니까.`,JPN:`私が生きてきた理由を否定された気分だったから。`,ENG:`It made me believe that my entire life had been a lie.`,TWN:`我就覺得自己活下去的理由被全盤否定。`},stage:{bg:`MAINSTREAM_345011`,slots:{L:null,C:null,R:null}}}];export{e as default};